    [ApiController]
    [Route("api/[controller]")]
    [Authorize]
    public class InvoicesController : ControllerBase
    {
        private readonly IInvoiceRepository _invoiceRepository;
        private readonly IAuthorizationService _authorizationService;

        public InvoicesController(IInvoiceRepository invoiceRepository, IAuthorizationService authorizationService)
        {
            _invoiceRepository = invoiceRepository;
            _authorizationService = authorizationService;
        }

        [HttpGet("{invoiceId}")]
        public async Task<IActionResult> GetInvoiceById(int invoiceId)
        {
            var invoice = await _invoiceRepository.GetByIdAsync(invoiceId);
            
            if (invoice == null)
            {
                return NotFound(new { message = "Invoice not found" });
            }

            var userId = User.FindFirstValue(ClaimTypes.NameIdentifier);
            var userTenantId = User.FindFirstValue("TenantId");
            var userRole = User.FindFirstValue(ClaimTypes.Role);

            if (string.IsNullOrEmpty(userId) || string.IsNullOrEmpty(userTenantId))
            {
                return Unauthorized(new { message = "Invalid user claims" });
            }

            if (invoice.TenantId.ToString() != userTenantId)
            {
                return Forbid();
            }

            var authResult = await _authorizationService.AuthorizeAsync(User, invoice, "ViewInvoicePolicy");
            if (!authResult.Succeeded)
            {
                return Forbid();
            }

            var invoiceDto = MapToDto(invoice, userRole);

            return Ok(invoiceDto);
        }

        private InvoiceDto MapToDto(Invoice invoice, string userRole)
        {
            var dto = new InvoiceDto
            {
                InvoiceId = invoice.InvoiceId,
                InvoiceNumber = invoice.InvoiceNumber,
                CustomerId = invoice.CustomerId,
                CustomerName = invoice.CustomerName,
                InvoiceDate = invoice.InvoiceDate,
                DueDate = invoice.DueDate,
                TotalAmount = invoice.TotalAmount,
                Status = invoice.Status,
                LineItems = invoice.LineItems?.Select(li => new LineItemDto
                {
                    LineItemId = li.LineItemId,
                    Description = li.Description,
                    Quantity = li.Quantity,
                    UnitPrice = li.UnitPrice,
                    TotalPrice = li.TotalPrice,
                    CanUpdate = CanUpdateLineItem(userRole, invoice.Status)
                }).ToList(),
                CanUpdateStatus = CanUpdateStatus(userRole, invoice.Status),
                CanUpdateAmount = CanUpdateAmount(userRole, invoice.Status),
                CanUpdateDueDate = CanUpdateDueDate(userRole, invoice.Status),
                CanDelete = CanDeleteInvoice(userRole, invoice.Status)
            };

            return dto;
        }

        private bool CanUpdateLineItem(string role, string invoiceStatus)
        {
            if (invoiceStatus == "Paid" || invoiceStatus == "Cancelled")
                return false;

            return role == "Admin" || role == "AccountingManager" || role == "Accountant";
        }

        private bool CanUpdateStatus(string role, string currentStatus)
        {
            if (role == "Admin" || role == "AccountingManager")
                return true;

            if (role == "Accountant" && currentStatus != "Paid")
                return true;

            return false;
        }

        private bool CanUpdateAmount(string role, string invoiceStatus)
        {
            if (invoiceStatus == "Paid" || invoiceStatus == "Cancelled")
                return false;

            return role == "Admin" || role == "AccountingManager";
        }

        private bool CanUpdateDueDate(string role, string invoiceStatus)
        {
            if (invoiceStatus == "Paid" || invoiceStatus == "Cancelled")
                return false;

            return role == "Admin" || role == "AccountingManager" || role == "Accountant";
        }

        private bool CanDeleteInvoice(string role, string invoiceStatus)
        {
            if (invoiceStatus == "Paid")
                return false;

            return role == "Admin" || role == "AccountingManager";
        }
