namespace InvoiceApi.Authorization
{
    using Microsoft.AspNetCore.Authorization;
    using System.Security.Claims;

    public class ViewInvoiceRequirement : IAuthorizationRequirement
    {
    }

    public class ViewInvoiceHandler : AuthorizationHandler<ViewInvoiceRequirement, Invoice>
    {
        protected override Task HandleRequirementAsync(
            AuthorizationHandlerContext context,
            ViewInvoiceRequirement requirement,
            Invoice invoice)
        {
            var userId = context.User.FindFirstValue(ClaimTypes.NameIdentifier);
            var userRole = context.User.FindFirstValue(ClaimTypes.Role);
            var userTenantId = context.User.FindFirstValue("TenantId");

            if (string.IsNullOrEmpty(userId) || string.IsNullOrEmpty(userTenantId))
            {
                return Task.CompletedTask;
            }

            if (invoice.TenantId.ToString() != userTenantId)
            {
                return Task.CompletedTask;
            }

            if (userRole == "Admin" || userRole == "AccountingManager")
            {
                context.Succeed(requirement);
                return Task.CompletedTask;
            }

            if (userRole == "Accountant")
            {
                context.Succeed(requirement);
                return Task.CompletedTask;
            }

            if (userRole == "SalesRep" && invoice.CreatedByUserId.ToString() == userId)
            {
                context.Succeed(requirement);
                return Task.CompletedTask;
            }

            return Task.CompletedTask;
        }
    }
}

namespace InvoiceApi
{
    using Microsoft.AspNetCore.Authorization;
    using InvoiceApi.Authorization;

    public class Startup
    {
        public void ConfigureServices(IServiceCollection services)
        {
            services.AddControllers();
            
            services.AddAuthorization(options =>
            {
                options.AddPolicy("ViewInvoicePolicy", policy =>
                    policy.Requirements.Add(new ViewInvoiceRequirement()));
            });

            services.AddSingleton<IAuthorizationHandler, ViewInvoiceHandler>();
        }

        public void Configure(IApplicationBuilder app, IWebHostEnvironment env)
        {
            app.UseRouting();
            app.UseAuthentication();
            app.UseAuthorization();
            app.UseEndpoints(endpoints =>
            {
                endpoints.MapControllers();
            });
        }
    }
